// Timestamp-Konverter. value: Unix s/ms oder ISO-String. Auto-Erkennung s vs ms.
async function run(input) {
  var value = (input && input.value);
  var unit = String((input && input.unit) || 'auto').toLowerCase();
  var ms;
  if (typeof value === 'number' || /^-?\d+$/.test(String(value))) {
    var num = Number(value);
    if (unit === 's') ms = num * 1000;
    else if (unit === 'ms') ms = num;
    else ms = String(Math.abs(Math.trunc(num))).length >= 12 ? num : num * 1000;
  } else {
    var parsed = Date.parse(String(value));
    if (isNaN(parsed)) return { fehler: 'Wert nicht erkannt (Unix-Zeit oder ISO-Datum erwartet).' };
    ms = parsed;
  }
  var d = new Date(ms);
  if (isNaN(d.getTime())) return { fehler: 'Ungueltiger Zeitwert.' };
  var diff = Date.now() - ms;
  function relativ(diffMs) {
    var past = diffMs >= 0;
    var s = Math.abs(diffMs) / 1000;
    var units = [['Jahr', 31536000], ['Monat', 2592000], ['Tag', 86400], ['Stunde', 3600], ['Minute', 60], ['Sekunde', 1]];
    var plurals = { 'Jahr': 'Jahren', 'Monat': 'Monaten', 'Tag': 'Tagen', 'Stunde': 'Stunden', 'Minute': 'Minuten', 'Sekunde': 'Sekunden' };
    for (var i = 0; i < units.length; i++) {
      var n = Math.floor(s / units[i][1]);
      if (n >= 1) {
        var word = n > 1 ? plurals[units[i][0]] : units[i][0];
        return (past ? 'vor ' : 'in ') + n + ' ' + word;
      }
    }
    return 'gerade eben';
  }
  var lesbar;
  try { lesbar = d.toLocaleString('de-DE'); } catch (e) { lesbar = d.toUTCString(); }
  return {
    unixSekunden: Math.floor(ms / 1000),
    unixMillis: ms,
    iso: d.toISOString(),
    lesbar: lesbar,
    relativ: relativ(diff)
  };
}
